func salaryRecurrenceValue(s Salary) string {
	if s.ID == "" {
		return "*-*-25"
	}
	return string(s.Recurrence)
}

func salaryPriorityValue(s Salary) string {
	if s.ID == "" {
		return "0"
	}
	return strconv.FormatInt(s.Priority, 10)
}

func formatAdjFloat(v float64) string {
	if v == 0 {
		return ""
	}
	return strconv.FormatFloat(v, 'f', -1, 64)
}

func rowActionTitle(isEdit bool) string {
	if isEdit {
		return "Save"
	}
	return "Add"
}

